export const qmActivities: Activity[] = [
  {"id":"qm-balloon-belly-breathing","title":"Balloon Belly Breathing","altNames":["Belly Breathing","Diaphragmatic Breathing","Balloon Breath"],"type":"Quiet","place":"Both","ageMin":6,"ageMax":12,"durationMin":15,"groupMin":null,"groupMax":null,"energy":1,"prep":"None","blurb":"Kids rest a hand on their belly and imagine inflating a balloon inside, watching it rise and fall to settle a wound-up body.","materials":["Open floor space or mats","Soft instrumental music (optional)"],"materialTags":["Open space","Music source"],"steps":["Have everyone lie on their backs or sit tall with one hand on the belly and one on the chest.","Tell them to imagine a favorite-color balloon living in their tummy.","On a slow nose breath, the belly balloon inflates and the lower hand rises while the chest stays still.","On a long mouth breath, let the balloon deflate and the belly hand sink back down.","Repeat for six to eight slow rounds, calling the rise and fall out loud at first.","Finish by asking how their body feels different than when they started."],"notes":"The hand on the belly is the whole trick: it gives kids visible proof they are breathing low, not high in the chest. If a child can only move the chest hand, have them lie down where gravity helps the belly lead.","safety":"Anyone who feels dizzy or lightheaded should stop, breathe normally, and sit up slowly.","ages":["g13","g46"],"rating":0,"media":[{"title":"Balloon Breathing — 5-Minute Guided Meditation for Kids","url":"https://www.youtube.com/watch?v=paTVMheICxM"}],"links":[{"label":"How-to & more ideas","url":"https://www.copingskillsforkids.com/deep-breathing-exercises-for-kids"}],"variations":["Place a small lightweight object like a paper cup on the belly so kids can watch it ride up and down.","Pair kids up so one narrates the balloon rising while the partner breathes, then switch."],"subsets":[["Younger kids do better lying down where the belly naturally leads."],[],["Cue them to keep the upper chest hand as still as a statue."],[],[],[]]},
  {"id":"qm-box-breathing-square","title":"Square Box Breathing","altNames":["Box Breathing","Four-Square Breathing","Tactical Breathing"],"type":"Quiet","place":"Both","ageMin":9,"ageMax":16,"durationMin":15,"groupMin":null,"groupMax":null,"energy":1,"prep":"Low","blurb":"Campers trace a square in the air while breathing in, holding, out, and holding for an equal four counts each, building steady calm focus.","materials":["Sidewalk chalk or paper and markers (optional)","Open space to sit"],"materialTags":["Sidewalk chalk","Paper","Markers","Open space"],"steps":["Draw a large square on the ground with chalk, or have each camper trace a square with a finger in the air.","Breathe in through the nose for four counts while tracing up the first side.","Hold the breath for four counts along the top side.","Breathe out through the mouth for four counts down the far side.","Hold empty for four counts along the bottom, completing the square.","Repeat for four to six full squares, counting slowly and evenly together."],"notes":"The equal four-four-four-four rhythm is what makes it work, so keep your counting pace slow and consistent. Older kids love that real athletes and first responders use this; framing it that way boosts buy-in.","safety":"Keep holds short and never force them; if holding feels uncomfortable, shorten the count to three or skip the holds.","ages":["g13","g46","g79","g1012"],"rating":0,"media":[{"title":"Guided Square Breathing for Children","url":"https://www.youtube.com/watch?v=PHQ7YZYRAms"}],"links":[{"label":"How-to & more ideas","url":"https://www.copingskillsforkids.com/deep-breathing-exercises-for-kids"}],"variations":["Trace the square on a real chalk square drawn big enough to walk one side per breath.","Lower the count to three each side for younger or anxious kids."],"subsets":[["A floor square turns it into a calm walking version."],[],[],[],[],[]]},
  {"id":"qm-five-finger-breathing","title":"Five-Finger Star Breathing","altNames":["Finger Tracing Breath","Five-Finger Breathing","Take Five Breathing"],"type":"Quiet","place":"Both","ageMin":6,"ageMax":14,"durationMin":15,"groupMin":null,"groupMax":null,"energy":1,"prep":"None","blurb":"Tracing slowly up and down each finger of a spread hand, campers breathe in on the way up and out on the way down for a calming hand-shaped roadmap.","materials":["No materials needed","Optional paper and markers to trace a hand"],"materialTags":["No materials","Paper","Markers"],"steps":["Spread one hand open like a star and hold the pointer finger of the other hand at the wrist.","Trace slowly up the outside of the thumb while breathing in through the nose.","Trace slowly down the inside of the thumb while breathing out through the mouth.","Continue up-and-down each finger, one breath per finger, all the way across the hand.","When you reach the pinky, trace back the other way to add five more breaths.","Switch hands and repeat for anyone who wants a second round."],"notes":"This is the best one for kids who need something to do with their hands when upset, and it travels anywhere with no gear. Slow the tracing finger way down; kids tend to rush it, which defeats the calming pace.","safety":"Use a gentle fingertip touch; remind kids not to dig nails into their skin while tracing.","ages":["g13","g46","g79"],"rating":0,"media":[{"title":"Five Finger Breathing — Guided Breathing Exercise for Kids","url":"https://www.youtube.com/watch?v=HQVZgpyVQ78"}],"links":[{"label":"How-to & more ideas","url":"https://www.copingskillsforkids.com/deep-breathing-exercises-for-kids"}],"variations":["Trace around a hand drawn on paper instead of a real hand for kids who like a keepsake.","Add a word on the in-breath and a word on the out-breath, like in-calm and out-go."],"subsets":[[],["In on the up-stroke is the rule for every finger."],["Out on every down-stroke keeps the rhythm honest."],[],[],[]]},
  {"id":"qm-bubble-wand-breaths","title":"Mindful Bubble Breaths","altNames":["Bubble Breathing","Slow Bubble Breaths","Calm Bubbles"],"type":"Quiet","place":"Outside","ageMin":6,"ageMax":12,"durationMin":15,"groupMin":null,"groupMax":null,"energy":1,"prep":"Low","blurb":"Using only their slowest, gentlest breath, campers see how long and unbroken a bubble they can blow, turning a deep exhale into something they can watch float away.","materials":["Bubble solution, small cups","Bubble wands or pipe-cleaner loops","Paper towels for spills"],"materialTags":["Paper cups","Pipe cleaners","Paper towels","Water source"],"steps":["Give each camper a small cup of bubble solution and a wand or bent pipe-cleaner loop.","Explain that a fast hard breath pops the bubble, so the goal is the slowest, softest exhale possible.","Have everyone take a calm nose breath, then blow one long gentle stream to grow a big bubble.","Watch the bubble drift and silently follow it with the eyes until it pops.","Try to beat your own record for the biggest or longest-floating bubble, breathing slowly each time.","Gather and talk about how slowing the breath down changed the bubbles and their bodies."],"notes":"The bubble is instant feedback: too forceful and it bursts, so kids self-correct toward a slow exhale without you nagging. Space campers out so bubble streams and elbows do not collide.","safety":"Keep bubble solution out of eyes and mouths; do not let kids drink or share solution cups.","ages":["g13","g46"],"rating":0,"media":[{"title":"Bubble Breathing & Mindfulness — Guided Meditation for Kids (Twinkl)","url":"https://www.youtube.com/watch?v=tCwQ51uazCg"}],"links":[{"label":"How-to & more ideas","url":"https://www.copingskillsforkids.com/deep-breathing-exercises-for-kids"}],"variations":["No solution on hand? Mime blowing an imaginary giant bubble that must never pop.","Make it a quiet challenge: the camper whose bubble floats the longest leads the next breath."],"subsets":[[],["Demonstrate one slow gentle stream versus a quick pop so the contrast is clear."],[],["Following the bubble with the eyes adds a focus-anchor element."],[],[]]},
  {"id":"qm-body-scan-melt","title":"Head-to-Toe Body Scan","altNames":["Body Scan","Melting Body Scan","Relaxation Scan"],"type":"Quiet","place":"Both","ageMin":8,"ageMax":16,"durationMin":15,"groupMin":null,"groupMax":null,"energy":1,"prep":"None","blurb":"Lying still, campers travel attention slowly from the top of the head down to the toes, noticing and softening each body part like ice melting in the sun.","materials":["Mats or towels to lie on","Quiet space"],"materialTags":["Open space"],"steps":["Have campers lie on their backs, arms at their sides, eyes closed or softly looking up.","In a slow calm voice, guide attention to the top of the head and invite it to relax.","Move the spotlight down slowly: face, shoulders, arms, hands, chest, belly, hips.","Continue down the legs to the feet and toes, pausing to soften each part.","Invite them to picture each body part melting heavy and warm into the floor.","End by noticing the whole body at once for a few breaths, then wiggle fingers and toes to wake up."],"notes":"Pace is everything; spend a few slow breaths on each region rather than racing down the body. A predictable head-to-toe order helps kids relax because they know what is coming next.","safety":"Spread campers out so no one gets stepped on, and have them rise slowly at the end to avoid head rush.","ages":["g13","g46","g79","g1012"],"rating":0,"media":[{"title":"Body Scan Meditation for Kids — 5 Minute Mindfulness","url":"https://www.youtube.com/watch?v=JL_22TU80Hs"}],"links":[{"label":"How-to & more ideas","url":"https://www.copingskillsforkids.com/deep-breathing-exercises-for-kids"}],"variations":["Shorten to head, belly, and feet only for younger or restless groups.","Add a tense-and-release at each body part for kids who relax better by squeezing first."],"subsets":[[],[],["Keep the spotlight moving in one steady direction so no part is skipped."],[],["The melting image gives wiggly kids something concrete to picture."],[]]},
  {"id":"qm-glitter-jar-focus","title":"Calm-Down Glitter Jar","altNames":["Glitter Jar","Calm Jar","Mind Jar","Settle Jar"],"type":"Quiet","place":"Both","ageMin":6,"ageMax":12,"durationMin":30,"groupMin":null,"groupMax":null,"energy":1,"prep":"Medium","blurb":"Campers make a sealed bottle of swirling glitter, then shake it and breathe slowly while the sparkles drift down, watching their busy thoughts settle just like the jar.","materials":["Clear plastic water bottles with caps, one each","Fine glitter, assorted colors","Clear school glue","Warm water source","Strong tape to seal caps"],"materialTags":["Glue","Water source","Masking tape"],"steps":["Fill each clear bottle most of the way with warm water.","Stir in a squeeze of clear glue and a small spoon of glitter, then top off with water.","Cap tightly and tape the lid shut so it stays sealed.","Shake the bottle to make a glitter storm, then set it down and watch.","As the glitter swirls, breathe slowly in and out until every speck has settled to the bottom.","Talk about how the swirling glitter is like racing thoughts, and how slow breathing helps them settle."],"notes":"More glue means slower, longer settling and more breaths; adjust the glue ratio to match your group's patience. Keep one finished jar in the calm corner all summer for kids who need to reset on their own.","safety":"Seal lids tightly with tape so glitter water cannot spill or be opened; wipe up wet floors right away.","ages":["g13","g46"],"rating":0,"links":[{"label":"How-to & more ideas","url":"https://www.copingskillsforkids.com/deep-breathing-exercises-for-kids"}],"variations":["Skip the glitter and layer in tiny torn paper bits if glitter is messy for your space.","Time how many breaths it takes to settle and try to stay calm and still the whole time."],"subsets":[[],["A small spoon of glitter is plenty; too much never settles."],["Counselors should do the final tight cap and tape."],[],["Cue one slow breath per few seconds while the glitter falls."],[]]},
  {"id":"qm-mindful-sound-bell","title":"Mindful Listening Bell","altNames":["Listening Bell","Sound Anchor","Ring and Listen","Bell Meditation"],"type":"Quiet","place":"Both","ageMin":7,"ageMax":16,"durationMin":15,"groupMin":null,"groupMax":null,"energy":1,"prep":"Low","blurb":"A single ringing sound becomes a focus anchor as campers raise a hand the instant they can no longer hear it, training deep stillness and attention.","materials":["A bell, chime, triangle, or anything that rings","Quiet space"],"materialTags":["Music source","Open space"],"steps":["Have campers sit comfortably, close their eyes, and rest their hands in their laps.","Explain that you will ring one sound, and they should listen to it fade all the way to silence.","Ring the bell once and let it sing.","The moment a camper can no longer hear any trace of the sound, they silently raise a hand.","When all hands are up, take a few slow breaths together in the new quiet.","Repeat two or three times, then ask what other small sounds they noticed in the silence."],"notes":"The fading tail of the sound is the anchor; a ringing chime works far better than a flat thud. The silent hand-raise keeps the room quiet and gives every kid a job, so no one calls out.","safety":"Keep the ringing volume gentle and never ring close to a camper's ear.","ages":["g13","g46","g79","g1012"],"rating":0,"media":[{"title":"The Listening Game — Cosmic Kids Zen Den","url":"https://www.youtube.com/watch?v=uUIGKhG_Vq8"}],"links":[{"label":"How-to & more ideas","url":"https://www.copingskillsforkids.com/deep-breathing-exercises-for-kids"}],"variations":["No bell? Tap a metal water bottle or sing a single sustained note and let it fade.","After the bell, keep listening and silently count how many other sounds you can find."],"subsets":[[],["Frame the goal as hearing the very last whisper of the sound."],[],["The silent raised hand keeps the whole exercise quiet."],[],[]]},
  {"id":"qm-gratitude-breath-circle","title":"Gratitude Breath Circle","altNames":["Gratitude Circle","Thankful Breaths","Grateful Round"],"type":"Quiet","place":"Both","ageMin":7,"ageMax":16,"durationMin":15,"groupMin":6,"groupMax":20,"energy":1,"prep":"None","blurb":"Going around a calm seated circle, each camper takes one slow breath and names a single thing they are thankful for, weaving breathing with a quiet wave of gratitude.","materials":["A small object to pass as a talking piece (optional)","Space to sit in a circle"],"materialTags":["Open space","No materials"],"steps":["Sit in a circle and take three slow group breaths to settle in.","Explain that on each turn, a camper takes one slow breath, then names one thing they are grateful for.","Start the round; the first camper breathes, shares, and the gratitude moves to the next person.","Listeners stay quiet and just breathe slowly while each person shares.","Pass a small talking object so everyone knows whose turn it is and silence is honored.","Close with one more group breath and a quiet thank-you to the circle."],"notes":"Keep shares to a single word or short phrase so the calm rhythm of breath-then-share does not break. Always allow a camper to pass; pressure to perform kills the safe, settled feeling.","safety":"Set a no-mocking rule so every share is respected; emotional safety is the whole point here.","ages":["g13","g46","g79","g1012"],"rating":0,"media":[{"title":"Gratitude Meditation for Kids — Guided Mindfulness Practice","url":"https://www.youtube.com/watch?v=_qpxWpGH11Q"}],"links":[{"label":"How-to & more ideas","url":"https://www.copingskillsforkids.com/deep-breathing-exercises-for-kids"}],"variations":["Theme each round, like grateful for something you can see, hear, or touch right now.","Have campers whisper their gratitude to keep the volume and energy extra low."],"subsets":[[],["One breath before sharing keeps it tied to the breathing practice."],[],[],["The talking piece prevents cross-talk and keeps it calm."],[]]},
  {"id":"qm-progressive-squeeze-relax","title":"Squeeze-and-Melt Muscle Relax","altNames":["Progressive Muscle Relaxation","Tense and Release","Spaghetti and Noodle","Robot to Ragdoll"],"type":"Quiet","place":"Both","ageMin":6,"ageMax":14,"durationMin":15,"groupMin":null,"groupMax":null,"energy":1,"prep":"None","blurb":"Campers squeeze each muscle group tight like a stiff robot, then let it flop loose like a wet noodle, feeling tension drain out of the body one part at a time.","materials":["Mats or floor space","Quiet area"],"materialTags":["Open space"],"steps":["Have campers sit or lie down comfortably with room to move arms and legs.","Tell them to scrunch their face up tight for five counts like a robot, then let it go soft.","Squeeze fists and arms tight for five counts, then drop them loose like noodles.","Tighten the belly and shoulders, hold, then release with a slow out-breath.","Curl and squeeze the legs and toes, hold, then let them flop heavy and relaxed.","Lie still and notice how loose and heavy the whole body feels now compared to the start."],"notes":"The contrast is the lesson: kids feel relaxation more clearly right after squeezing, so make the tense part dramatic. Pair each release with a slow out-breath to link it back to breathing.","safety":"Tell kids to squeeze firmly but never to the point of pain or cramping, and to stop if anything hurts.","ages":["g13","g46","g79"],"rating":0,"media":[{"title":"Progressive Muscle Relaxation for Kids","url":"https://www.youtube.com/watch?v=cDKyRpW-Yuc"}],"links":[{"label":"How-to & more ideas","url":"https://www.copingskillsforkids.com/deep-breathing-exercises-for-kids"}],"variations":["Use a robot-to-ragdoll story where they slowly power down part by part.","Pretend to squeeze juice from a lemon in each hand, then drop the lemon and relax."],"subsets":[[],["Make the robot squeeze big and obvious so the release feels dramatic."],[],["Tie every release to a long slow out-breath."],[],[]]},
  {"id":"qm-mindful-slow-walk","title":"Slow Mindful Walk","altNames":["Mindful Walking","Walking Meditation","Slow Motion Walk","Footstep Awareness"],"type":"Quiet","place":"Outside","ageMin":8,"ageMax":16,"durationMin":15,"groupMin":null,"groupMax":null,"energy":1,"prep":"Low","blurb":"Walking in extreme slow motion along a quiet path, campers feel every part of each footstep and let their breath match their pace for a moving meditation.","materials":["A safe flat path or open grass area","Optional cones to mark a lane"],"materialTags":["Open space","Cones"],"steps":["Mark a short straight lane and have campers spread out along it facing the same way.","Explain they will walk as slowly as possible, feeling each foot lift, move, and land.","Begin walking in slow motion, breathing in as one foot lifts and out as it lands.","Keep eyes soft and down a few steps ahead, staying silent the whole way.","At the end of the lane, pause, take three slow breaths, and turn to walk back just as slowly.","Gather and share one thing they noticed about their feet, their breath, or the ground."],"notes":"Slower is the challenge, not faster; kids who race the lane have missed the point, so model an almost comically slow pace. Spacing them out prevents bumping and the giggles that come with crowding.","safety":"Choose a flat, obstacle-free path and keep enough space between campers so no one collides or trips.","ages":["g13","g46","g79","g1012"],"rating":0,"media":[{"title":"Mindful Walking — Cosmic Kids Zen Den","url":"https://www.youtube.com/watch?v=0P3Deuv8tbc"}],"links":[{"label":"How-to & more ideas","url":"https://www.copingskillsforkids.com/deep-breathing-exercises-for-kids"}],"variations":["Walk barefoot on soft safe grass to add the feeling of the ground underfoot.","Have campers silently name the parts of each step in their head: lift, move, place."],"subsets":[[],["Stress that the goal is the slowest walk, not finishing first."],["Linking each step to in-and-out breaths makes it a true moving meditation."],[],[],[]]},
  {"id":"qm-calm-color-doodle","title":"Calm-Color Breathing Doodle","altNames":["Mindful Doodling","Calm Coloring","Breathing Drawing","Zentangle Lite"],"type":"Quiet","place":"Both","ageMin":7,"ageMax":16,"durationMin":30,"groupMin":null,"groupMax":null,"energy":1,"prep":"Low","blurb":"With each slow breath, campers draw one looping line or fill one small shape in a soothing color, letting a quiet repetitive doodle and the breath calm the mind together.","materials":["Paper, one sheet each","Crayons or markers in soft calm colors","Smooth table or clipboard"],"materialTags":["Paper","Crayons","Markers"],"steps":["Give each camper a sheet of paper and a handful of calm-colored crayons or markers.","Have everyone take three slow settling breaths before picking up a color.","On each slow in-breath, draw one gentle loop, swirl, or line.","On each slow out-breath, fill or color one small section of the drawing.","Keep going breath by breath with no goal picture in mind, just letting the page fill.","After several minutes, stop, look at the page, and take one last calm breath together."],"notes":"There is no right picture; tell kids upfront that abstract loops and patterns are the goal so no one freezes over what to draw. The breath-paired rhythm is what separates this from regular coloring, so keep cueing the breaths.","safety":"Keep markers capped when not in use and remind kids not to put marker tips near eyes or mouths.","ages":["g13","g46","g79","g1012"],"rating":0,"media":[{"title":"Colour Your Breath — Mindful Art for Kids","url":"https://www.youtube.com/watch?v=VXs0czMhsZw"}],"links":[{"label":"How-to & more ideas","url":"https://www.copingskillsforkids.com/deep-breathing-exercises-for-kids"}],"variations":["Pick one calm color for the whole page and explore every shade and pressure it can make.","Trade pages halfway and gently add to a partner's calm doodle, breathing as you go."],"subsets":[[],["Three settling breaths first sets the calm tone before drawing."],["One mark per breath is what links the doodle to the breathing."],[],["Reassure kids that abstract loops with no picture is exactly right."],[]]},
];
